  var searchQuery = '';

  function render() {
    var grid = document.getElementById('grid');
    var filtered = bookmarks.slice();

    if (currentCollection !== 'all') {
      filtered = filtered.filter(function(b) { return b.collection === currentCollection; });
    }

    if (searchQuery) {
      var q = searchQuery.toLowerCase();
      filtered = filtered.filter(function(b) {
        return b.title.toLowerCase().indexOf(q) !== -1 ||
               b.url.toLowerCase().indexOf(q) !== -1 ||
               b.tags.some(function(t) { return t.toLowerCase().indexOf(q) !== -1; });
      });
    }

    if (!filtered.length) {
      grid.innerHTML = '<div class="empty-state"><div class="empty-state-icon">&#x1F4D1;</div><div class="empty-state-text">No bookmarks yet</div></div>';
    } else {
      grid.innerHTML = filtered.map(function(b) {
        var domain = '';
        try { domain = new URL(b.url).hostname.replace(/^www\./, ''); } catch (_) {}
        return '<div class="card">' +
          '<div class="card-actions"><button class="card-del" data-id="' + b.id + '" title="Delete">&#x2715;</button></div>' +
          '<div class="card-top">' +
            '<div class="card-favicon">' +
              '<img src="https://www.google.com/s2/favicons?domain=' + domain + '&sz=32" alt="" onerror="this.parentNode.textContent=\'&#x1F310\';this.style.display=\'none\'">' +
            '</div>' +
            '<div class="card-title">' + esc(b.title) + '</div>' +
          '</div>' +
          '<div class="card-url">' + esc(domain + b.url.slice(b.url.indexOf(domain) + domain.length)) + '</div>' +
          '<div class="card-tags">' + b.tags.map(function(t) { return '<span class="tag">' + esc(t) + '</span>'; }).join('') + '</div>' +
          '<div class="card-date">Added ' + b.date + '</div>' +
        '</div>';
      }).join('');
    }

    var counts = {};
    bookmarks.forEach(function(b) {
      counts[b.collection] = (counts[b.collection] || 0) + 1;
      counts._all = (counts._all || 0) + 1;
    });
    document.getElementById('count-all').textContent = counts._all || 0;
    document.getElementById('count-dev').textContent = counts.dev || 0;
    document.getElementById('count-design').textContent = counts.design || 0;
    document.getElementById('count-read').textContent = counts.read || 0;
    document.getElementById('count-reference').textContent = counts.reference || 0;
    document.getElementById('count-imported').textContent = counts.imported || 0;

    document.querySelectorAll('.card-del').forEach(function(btn) {
      btn.addEventListener('click', function(e) {
        e.stopPropagation();
        var id = btn.getAttribute('data-id');
        bookmarks = bookmarks.filter(function(b) { return b.id !== id; });
        save();
        render();
      });
    });
  }

